const synthetics = require("Synthetics");
const log = require("SyntheticsLogger");

// Outside-in uptime probe: load the live app and assert a 2xx.
const uptimeCheck = async function () {
  const url = process.env.TARGET_URL || "https://share.abheenash.com/";
  const page = await synthetics.getPage();
  const response = await page.goto(url, { waitUntil: "domcontentloaded", timeout: 30000 });
  const status = response ? response.status() : 0;
  if (status < 200 || status > 299) {
    throw new Error(`Uptime check failed for ${url}: HTTP ${status}`);
  }
  log.info(`Uptime OK for ${url}: HTTP ${status}`);
};

exports.handler = async () => {
  return await uptimeCheck();
};
